class Solution:
    def minimumTimeToInitialState(self, word, k):
        n = len(word)
        for t in range(1, n+1):
            start = t * k
            if start >= n:
                return t
            suffix = word[start:]
            if word.startswith(suffix):
                return t
        return (n + k - 1) // k

